// Modified from https://zhuanlan.zhihu.com/p/373623264
// 获取 Obsidian 中的所有 Markdown 文件
countTimes("Paget")

function countTimes(term){
dv.header(2, term)
const files = app.vault.getMarkdownFiles()

// 将带有标签的文件以及行筛选出来
let arr = files.map( async(file) => {
//turn all the content into an array
  const content = await app.vault.cachedRead(file)
  let lines = await content.split("\n").filter(line => line.includes(term))
    return ["[["+file.name.split(".")[0]+"]]", lines]
})

// 生成表格，如果要将当前的文件排除的话，请修改其中的排除文件
Promise.all(arr).then(values => {
	const exists = values.filter(value => value[1][0] && value[0] != "[[測試dataview]]" && value[0] != "[[Obsidian 使用規則筆記]]" && value[0] != "[[0交換考]]" && value[0] != "[[1顯示交換考題數]]")
	dv.table(["file", "lines"], exists)
})
}
